def count_successful_villagers(N):
    successful_villagers = 0
    for i in range(1, N + 1):
        fruits = i
        layers = 0
        while fruits > 0 and layers < 10:
            layers += 1
            fruits -= layers
        if fruits == 0 and layers <= 10:
            successful_villagers += 1
    return successful_villagers
